external_knowledge:
- 'specific plant' refers to plant with plant_id 1;
- 'certain day' refers to access_date 2022-01-02;
- 'user with a particular identifier' refers to user_id 0.

- 'Zea mays' refers to corn or maize, a widely cultivated cereal crop;
- 'Clay' soil is characterized by its dense and sticky texture and has significant implications for plant growth;
- 'N192seed #9' is a specific cultivar or variety of corn, indicating a unique genetic composition.

sql:
SELECT plant_name, species
FROM plant
WHERE plant_id = 1;

SELECT u.username, u.email
FROM user u
JOIN data_access da ON u.user_id = da.user_id
WHERE da.access_date = (
    SELECT MAX(access_date) FROM data_access
);

SELECT root_ontology
FROM root_data
WHERE root_id = 1;

SELECT plant_type, COUNT(*)
FROM plant
GROUP BY plant_type;

SELECT plant_name, plant_type, species, ACOS(plant_id)
FROM plant
WHERE plant_id > 10;

SELECT plant_name
FROM plant
WHERE plant_type = 'Maize' AND genotype = 'B73';

SELECT plant.plant_name, image_metadata.image_file_name
FROM plant
JOIN image_metadata ON plant.plant_id = image_metadata.plant_id;

SELECT plant_name 
FROM plant 
WHERE plant_id = (SELECT MAX(plant_id) FROM plant);

